#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding first-responder-assessment (15 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    preferred_name:string! \
    gender_identity:string! \
    ethnicity:string! \
    preferred_language:string! \
    interpreter_required:string! \
    emergency_contact_name:string! \
    emergency_contact_phone:string! \
    emergency_contact_relationship:string! \
    --htmx

cargo loco generate scaffold assessment_role_qualifications \
    assessment:references \
    role_type:string! \
    role_type_other:text! \
    employer_organisation:string! \
    station_base:string! \
    years_of_service:double \
    registration_number:string! \
    registration_body:string! \
    registration_expiry_date:date \
    highest_qualification:string! \
    qualification_details:text! \
    driving_licence_category:string! \
    blue_light_trained:string! \
    role_notes:text! \
    --htmx

cargo loco generate scaffold assessment_physical_fitness \
    assessment:references \
    cardiovascular_fitness:string! \
    shuttle_run_level:int \
    vo2_max:double \
    muscular_strength:string! \
    grip_strength_kg:double \
    manual_handling_competency:string! \
    patient_carry_ability:string! \
    flexibility_mobility:string! \
    balance_coordination:string! \
    resting_heart_rate_bpm:int \
    blood_pressure_systolic:int \
    blood_pressure_diastolic:int \
    physical_fitness_notes:text! \
    --htmx

cargo loco generate scaffold assessment_clinical_skills \
    assessment:references \
    basic_life_support:string! \
    advanced_life_support:string! \
    airway_management:string! \
    iv_cannulation:string! \
    drug_administration:string! \
    trauma_assessment:string! \
    immobilisation_splinting:string! \
    ecg_interpretation:string! \
    patient_assessment:string! \
    triage_competency:string! \
    paediatric_competency:string! \
    obstetric_competency:string! \
    clinical_skills_notes:text! \
    --htmx

cargo loco generate scaffold assessment_equipment_vehicle \
    assessment:references \
    defibrillator_competency:string! \
    monitor_competency:string! \
    ventilator_competency:string! \
    suction_competency:string! \
    stretcher_competency:string! \
    scoop_competency:string! \
    ambulance_driving:string! \
    emergency_driving:string! \
    vehicle_daily_inspection:string! \
    equipment_check_competency:string! \
    radio_communications:string! \
    equipment_vehicle_notes:text! \
    --htmx

cargo loco generate scaffold assessment_communication_skills \
    assessment:references \
    patient_communication:string! \
    relative_communication:string! \
    handover_competency:string! \
    documentation_competency:string! \
    multidisciplinary_teamwork:string! \
    conflict_resolution:string! \
    safeguarding_awareness:string! \
    breaking_bad_news:string! \
    communication_notes:text! \
    --htmx

cargo loco generate scaffold assessment_psychological_readiness \
    assessment:references \
    stress_management:string! \
    resilience_level:string! \
    ptsd_screening:string! \
    ptsd_screening_result:string! \
    critical_incident_exposure:string! \
    critical_incident_details:text! \
    critical_incident_debriefed:string! \
    sleep_quality:string! \
    burnout_risk:string! \
    decision_making_under_pressure:string! \
    emotional_regulation:string! \
    psychological_notes:text! \
    --htmx

cargo loco generate scaffold assessment_occupational_health \
    assessment:references \
    vision_test:string! \
    vision_corrected:string! \
    hearing_test:string! \
    hearing_aid_required:string! \
    immunisation_status:string! \
    hepatitis_b_immune:string! \
    current_medications:text! \
    substance_misuse_screen:string! \
    musculoskeletal_issues:string! \
    musculoskeletal_details:text! \
    respiratory_issues:string! \
    respiratory_details:text! \
    skin_conditions:string! \
    skin_condition_details:text! \
    sickness_absence_days:int \
    occupational_health_notes:text! \
    --htmx

cargo loco generate scaffold assessment_cpd_training \
    assessment:references \
    cpd_hours_last_year:double \
    cpd_hours_required:double \
    mandatory_training_complete:string! \
    bls_recertification_date:date \
    als_recertification_date:date \
    manual_handling_recertification_date:date \
    safeguarding_training_date:date \
    infection_control_training_date:date \
    major_incident_training:string! \
    major_incident_training_date:date \
    mentoring_capability:string! \
    clinical_supervision_attendance:string! \
    reflective_practice:string! \
    cpd_training_notes:text! \
    --htmx

cargo loco generate scaffold assessment_fitness_decision \
    assessment:references \
    overall_fitness:string! \
    restrictions_details:text! \
    reassessment_required:string! \
    reassessment_date:date \
    remedial_actions:text! \
    referrals_required:text! \
    assessor_name:string! \
    assessor_role:string! \
    assessor_registration:string! \
    assessment_date:date \
    countersignature_name:string! \
    countersignature_date:date \
    fitness_decision_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    physical_fitness_level:string! \
    clinical_skills_level:string! \
    equipment_vehicle_level:string! \
    communication_level:string! \
    psychological_level:string! \
    overall_competency:string! \
    overall_fitness:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
